using System.Data;using System.Diagnostics;using System.Text.RegularExpressions;using Dapper;using JH.QueryStudio.Api.Data;using JH.QueryStudio.Api.Domain;using Microsoft.Data.SqlClient;using Microsoft.Data.Sqlite;
namespace JH.QueryStudio.Api.Services;
public interface IQuerySecurityService{IReadOnlyList<RiskFinding> Analyze(string sql,bool production);}public sealed class QuerySecurityService:IQuerySecurityService{public IReadOnlyList<RiskFinding> Analyze(string sql,bool prod){var f=new List<RiskFinding>();var s=Regex.Replace(sql,@"--.*?$|/\*.*?\*/","",RegexOptions.Singleline|RegexOptions.Multiline|RegexOptions.IgnoreCase);if(Regex.IsMatch(s,@"\bupdate\b(?![\s\S]*?\bwhere\b)",RegexOptions.IgnoreCase))f.Add(new("UPDATE_WITHOUT_WHERE","High","UPDATE sin cláusula WHERE."));if(Regex.IsMatch(s,@"\bdelete\s+from\b(?![\s\S]*?\bwhere\b)",RegexOptions.IgnoreCase))f.Add(new("DELETE_WITHOUT_WHERE","High","DELETE sin cláusula WHERE."));foreach(var p in new[]{"drop database","drop table","truncate table"})if(Regex.IsMatch(s,@"\b"+Regex.Escape(p).Replace("\\ ",@"\s+")+@"\b",RegexOptions.IgnoreCase))f.Add(new("DANGEROUS_DDL","Critical",$"Sentencia peligrosa detectada: {p.ToUpperInvariant()}."));if(prod&&Regex.IsMatch(s,@"\b(insert|update|delete|merge|drop|truncate|alter)\b",RegexOptions.IgnoreCase))f.Add(new("PRODUCTION_CHANGE","Critical","Cambio de datos o estructura en ambiente Producción."));return f;}}
public interface IMetadataService{Task<IReadOnlyList<DbObjectNode>> GetTreeAsync(Guid connectionId,string? database,CancellationToken ct);}public sealed class SqlServerMetadataService(IConnectionService cs):IMetadataService{public async Task<IReadOnlyList<DbObjectNode>> GetTreeAsync(Guid id,string? database,CancellationToken ct){var p=await cs.GetAsync(id)??throw new InvalidOperationException("Conexión no encontrada");await using var cn=new SqlConnection(cs.BuildConnectionString(p,database));var rows=await cn.QueryAsync<(string SchemaName,string ObjectName,string ObjectType,string? ColumnName)>("select s.name SchemaName,o.name ObjectName,o.type_desc ObjectType,c.name ColumnName from sys.objects o join sys.schemas s on s.schema_id=o.schema_id left join sys.columns c on c.object_id=o.object_id where o.type in ('U','V','P','FN','IF','TF','TR') order by s.name,o.name,c.column_id");return rows.GroupBy(r=>r.SchemaName).Select(g=>new DbObjectNode(g.Key,g.Key,"schema",g.Key,g.GroupBy(x=>new{x.ObjectName,x.ObjectType}).Select(o=>new DbObjectNode($"{g.Key}.{o.Key.ObjectName}",o.Key.ObjectName,o.Key.ObjectType.Contains("VIEW")?"view":o.Key.ObjectType.Contains("TABLE")?"table":"routine",g.Key,o.Where(x=>x.ColumnName!=null).Select(x=>new DbObjectNode($"{g.Key}.{o.Key.ObjectName}.{x.ColumnName}",x.ColumnName!,"column",g.Key,Array.Empty<DbObjectNode>())).ToList())).ToList())).ToList();}}
public interface IQueryExecutor{Task<QueryExecutionResult> ExecuteAsync(Guid connectionId,string? database,string sql,int maxRows,CancellationToken ct);}public sealed class SqlServerQueryExecutor(IConnectionService cs,IHistoryService hs):IQueryExecutor{public async Task<QueryExecutionResult> ExecuteAsync(Guid cid,string? db,string sql,int maxRows,CancellationToken ct){var p=await cs.GetAsync(cid)??throw new InvalidOperationException("Conexión no encontrada");var sw=Stopwatch.StartNew();var sets=new List<QueryResultSet>();var messages=new List<string>();int affected=0;string? err=null;int? line=null;try{await using var cn=new SqlConnection(cs.BuildConnectionString(p,db));cn.InfoMessage+=(_,e)=>messages.Add(e.Message);await cn.OpenAsync(ct);await using var cmd=new SqlCommand(sql,cn){CommandTimeout=p.Timeout};await using var r=await cmd.ExecuteReaderAsync(ct);do{var cols=Enumerable.Range(0,r.FieldCount).Select(r.GetName).ToList();var rows=new List<Dictionary<string,object?>>();while(await r.ReadAsync(ct)&&rows.Count<maxRows){rows.Add(cols.ToDictionary(c=>c,c=>r[c] is DBNull?null:r[c]));}sets.Add(new(cols,rows,rows.Count));}while(await r.NextResultAsync(ct));affected=r.RecordsAffected;sw.Stop();var hid=await hs.AddAsync(cid,db??p.DefaultDatabase??"master",sql,sw.ElapsedMilliseconds,sets.Sum(x=>x.RowCount),true,null);return new(hid,true,sw.ElapsedMilliseconds,affected,sets,messages,null,null);}catch(SqlException ex){sw.Stop();err=ex.Message;line=ex.LineNumber;var hid=await hs.AddAsync(cid,db??"",sql,sw.ElapsedMilliseconds,0,false,err);return new(hid,false,sw.ElapsedMilliseconds,0,sets,messages,err,line);}}}
public interface IHistoryService{Task<Guid> AddAsync(Guid cid,string db,string sql,long ms,int rows,bool ok,string? err);Task<IEnumerable<QueryHistory>> ListAsync();}public sealed class HistoryService(LocalDatabase db):IHistoryService{public async Task<Guid> AddAsync(Guid cid,string d,string sql,long ms,int rows,bool ok,string? err){var h=new QueryHistory(Guid.NewGuid(),cid,d,sql,ms,rows,ok,err,DateTimeOffset.UtcNow,false);await using var c=new SqliteConnection(db.ConnectionString);await c.ExecuteAsync("insert into QueryHistory values(@Id,@ConnectionId,@DatabaseName,@Sql,@DurationMs,@RowCount,@Success,@Error,@ExecutedAt,@IsFavorite)",h);return h.Id;}public async Task<IEnumerable<QueryHistory>> ListAsync(){await using var c=new SqliteConnection(db.ConnectionString);return await c.QueryAsync<QueryHistory>("select * from QueryHistory order by ExecutedAt desc limit 200");}}
